var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"꺄아악! 방금 봤지?! 쥐가 내 팔뚝보다 커!","JPN":"きゃーっ！　今のみた！？　アタシの腕よりおっきいネズミ！","ENG":"Aaaah! Did you just see that?! That rat's bigger than my arm!","TWN":"啊～～！你有看到嗎？那隻老鼠比我的手臂還大！"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"여긴 대정화 전쟁 이후 폐쇄된 지하철도입니다, 휴먼.","JPN":"ここは大浄化戦争以降、閉鎖された地下鉄です、ヒューマン。","ENG":"This underground railway has been closed down since the Grand Purification War, human.","TWN":"人類，這裡是淨化之戰後荒廢的地鐵。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"팔뚝만큼 커다란 쥐나 손바닥만 한 바퀴벌레가 있어도 이상할 것 없죠.","JPN":"腕ほどの大きさのネズミや、手のひらサイズのゴキブリがいてもおかしくありません。","ENG":"Giant rats and cockroaches are hardly an anomaly in this place.","TWN":"有跟手臂一樣大的老鼠，或是跟手掌一樣大的蟑螂，完全不足為奇。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"……그 바퀴벌레, 혹시 날아다니기도 할까?","JPN":"……そのゴキブリ、飛んだりする？","ENG":"Those roaches don't fly… do they?","TWN":"……那蟑螂…會飛嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"마침 저기 한 마리 있군요. 확인해 보시겠습니까.","JPN":"ちょうどあそこに1匹いますね。確かめてみますか？","ENG":"I see one right there. Would you like to find out?","TWN":"那裡剛好有隻蟑螂，要確認看看嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"또 언니 놀리지, 너? 자꾸 그러면 여기다 버리고 간다?","JPN":"もう！　またお姉ちゃんをからかって！　そんなことしたらここに置いていくよ？","ENG":"Stop messing with me! Or I'll leave you here all by yourself!","TWN":"你是不是又在鬧我！再這樣我要把你扔在這裡喔！"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"휴먼들은 참 제멋대로군요. 협박해서 끌고 나올 때는 언제고.","JPN":"ヒューマンというのは実に身勝手ですね。脅迫して無理やり連れてきたのに置いていくとは。","ENG":"You humans are such fickle creatures. Just moments ago, you threatened to tie me up if I didn't join you.","TWN":"人類真是任性，明明剛才是你硬把我帶到這裡的。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"애초에 어떤 근거로 엠마가 여기에 있다고 확신하는 겁니까.","JPN":"そもそも、どういった根拠でここにエマがいると確信しているのですか？","ENG":"On what basis are you so certain that Emma is here?","TWN":"請問你確定愛瑪就在這裡的根據是什麼？"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"별로 확신해서 온 건 아냐. 여기에도 없으면 찾기 글렀다는 거지.","JPN":"別に確信したからここに来たわけじゃないよ。\\nただ、ここにもいなかったらこれ以上の捜索はもう無理ってことになるだけ……","ENG":"I'm not certain about anything, really. I'm just saying if she's not here either… it's hopeless.","TWN":"我不是因為確定才來的，是因為這裡也沒有的話，可能有點不妙。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"이 근방 갱단들 대부분이 원장님한테 신세진 적 있다는 얘기는 저번에 해 줬지?","JPN":"この辺のギャングのほとんどが院長にお世話になったことがあるって話はこの前したよね？","ENG":"Did I tell you how most gangs around here owe the headmaster a favor?","TWN":"我上次有跟你說過吧？這附近的幫派大部分都欠院長人情。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그렇지만 맛이 간 약쟁이나 연고 없는 범죄자들은 그런 사정 신경 안 쓰거든.","JPN":"でもラリったジャンキーや縁故のない犯罪者たちは、そんなこと気にしないんだ。","ENG":"But junkies and petty criminals off on their own don't give a crap about that sort of thing.","TWN":"不過還是有些六親不認的毒蟲，或是白目的罪犯，沒在管什麼人情世故的。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"엠마란 아이가 인신매매나 살인 같은 강력범죄의 표적이 됐을지도 모른다는 말이군요. 이해했습니다.","JPN":"エマという子が人身売買もしくは殺人といった凶悪犯罪の標的になったかもしれないということですね。理解しました。","ENG":"You mean Emma may be a target of human trafficking or other felonies such as murder. Duly noted.","TWN":"明白，意思是愛瑪可能會成為人口販子，或是壞人的目標對吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그리고 이 앞은 지반이 부실하니 옆으로 붙어서 가죠.","JPN":"そしてこの先は地盤が緩くなっているので、壁に沿って進みましょう。","ENG":"Let us stay close to the walls as the ground here is prone to sinking.","TWN":"另外，前面的路危險，必須靠著旁邊走。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"얘가 잘 말하다 갑자기 뭐래. 금 하나 안 가 있는데.","JPN":"急にどういうこと？　ひび一本すら見えないよ？","ENG":"Uh… Okay? That's pretty random. I don't even see any cracks on the ground.","TWN":"話說到一半怎麼突然提到這個？路明明就好好的，也沒裂開？"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그러면 당신의 이해를 돕기 위해 이 콘크리트 파편을 던져 보겠습니다.","JPN":"それでは、あなたの理解を助けるためにこのコンクリートの破片を投げてみます。","ENG":"Then allow me to throw this piece of concrete to facilitate your understanding.","TWN":"我現在要丟這個混凝土碎片，幫助你釐清現況。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"무, 무너졌잖아……?","JPN":"く、崩れちゃった……？","ENG":"I-it just crumbled down!","TWN":"塌…塌咧……？"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"침식파로 인해 내부가 부식된 겁니다. 이런 곳에서는 외견상 문제가 없어도 주의해야죠.","JPN":"侵食波によって内部が腐食しています。このような場所では見かけ上問題がなくても注意しなければなりません。","ENG":"The Corruption Ray has corroded the foundation from inside out. One must always exercise caution in a place like this even in absence of ostensible dangers.","TWN":"裡面因為侵蝕波的關係遭到腐蝕，在這種地方，就算表面看起來沒問題也要格外小心。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"진짜 신기하다……. 어디서 그런 얘길 들은 거야?","JPN":"すごいね……そんなことどこで学んだの？","ENG":"That's incredible… Where did you hear stuff like that?","TWN":"真奇妙……這些都從哪聽來的？"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"말씀드렸다시피 저는 기계입니다. 구조물의 취약부를 감지하는 일은 어렵지 않습니다.","JPN":"申し上げたとおり私は機械です。構造物の脆弱性を感知することは難しくありません。","ENG":"As I've already told you, I'm a machine. Detecting structural integrity or the lack thereof is hardly a challenge.","TWN":"就如同我跟你說過的，我是個機器，要感應到建築物的弱點並非難事。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이제 제 말을 믿으시겠습니까, 휴먼.","JPN":"これで私の話を信じますか、ヒューマン。","ENG":"Do you believe me now, human?","TWN":"人類，現在你相信我的話了嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"웃기시네. 너처럼 사람이랑 똑같이 생긴 기계가 세상에 어디 있냐.","JPN":"笑わせないで。こんな人間そっくりの機械があるわけないでしょ。","ENG":"Yeah, right. Machines don't look as human as you do.","TWN":"笑死！怎麼可能有機器人長得跟人一樣啦！"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"여기 있습니다.","JPN":"ここにあります。","ENG":"But I do.","TWN":"近在眼前。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"우쭈쭈. 그래, 다 알아요. 알아. 언니도 너 같을 때가 있었거든.","JPN":"はいはい、わかりました。お姉ちゃんにもそういう時代があったな。","ENG":"Sure, sure. I get it. I really do. I've been through that phase.","TWN":"嘖嘖，好好好，我也曾經跟你一樣。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"혹시 난 인간이 아닐지도 몰라! 카운터? 아니면 전혀 다른 새로운 초능력자?!","JPN":"もしかしたらアタシは人間じゃないかも！　カウンター？　それとも新しい超能力者！？","ENG":"\\"What if I'm not human?! Maybe I'm a Counter? Or some other super-powered metahuman?!\\"","TWN":"懷疑自己可能不是人！是制裁者？或者是全新的超能力者？！"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그런 유치한 상상은 네 망상 노트에만 적어놔. 커서 놀림 받으면 진짜 쪽팔리거든.","JPN":"そんなお子ちゃまのごっこ遊びは日記に書くだけにしておいて。大きくなったらからかわれて恥ずかしいだけなんだから。","ENG":"Seriously, though. Just keep those fantasies to yourself. It can be super embarrassing when others tease you when you're older.","TWN":"這種幼稚的想像就藏在心裡吧，否則等你長大後被嘲笑的話，真的會很丟臉的喔！"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"에이, 또 삐졌어? 언니가 부둥부둥 해 줘?","JPN":"ねえ、すねちゃった？　お姉ちゃんがおんぶでもしてあげよっか？","ENG":"Aww, did I upset you again? Want me to pat you on your head to make you feel better?","TWN":"真是的，又耍脾氣啦？要姊姊給你呼呼嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"엠마란 아이의 인상착의나 설명해 보십시오. 휴먼.","JPN":"いいから、エマという子の外見を説明してください、ヒューマン。","ENG":"Just describe what this Emma child looks like, human.","TWN":"人類，可以說明一下愛瑪的穿著或是長相嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"응? 엠마?","JPN":"うん？　エマ？","ENG":"Hm? Emma?","TWN":"嗯？愛瑪嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"머리카락은 갈색에, 양갈래로 묶었고 키는 너보다 조금 작아. 한 이만큼 되려나.","JPN":"茶髪にツインテール、背はあんたより少し低い。これくらいの情報でもいい？","ENG":"She's got brown hair in pigtails; a little shorter than you. About yay high, I think?","TWN":"咖啡色的頭髮，有雙馬尾，身高比你矮一點，差不多這麼高吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"못생기고 얼룩덜룩한 수제 헝겊 인형을 가지고 다닙니까?","JPN":"ブサイクでまだら模様の手縫いのぬいぐるみを持ち歩いていますか？","ENG":"Does she perchance carry a ragged, ugly cloth doll?","TWN":"抱著一個醜醜的破娃娃到處跑嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"야, 그게 왜 못생겨? 내가 얼마나 정성들여 만들어 준 건데?","JPN":"ちょっと、ブサイクってひどくない？　アタシが心を込めて作ったものなんだよ？","ENG":"Hey, it's not ugly! I put a lot of work into making that thing!","TWN":"什麼醜？哪裡醜？那可是我很用心做的好嗎！"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"가지고 다닌다는 뜻으로 이해하겠습니다.","JPN":"持っているということで理解しました。","ENG":"I'll take that as a yes.","TWN":"我就當你是默認的意思。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"찾았습니다. 저기 모퉁이 뒤, 파손된 외벽 균열 사이에 숨어 있군요.","JPN":"見つけました。あの角の裏、破損した外壁の亀裂の間に隠れていますね。","ENG":"I've found her. She's hiding between the cracks of the damaged wall around that corner.","TWN":"找到了，她就躲在轉彎處後面，剝落的牆壁裂縫中間。"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"호라이즌. 너 아무리 삐졌어도 그렇지, 그런 거짓말은 하면 안 돼.","JPN":"ホライズン、すねているからって嘘をつくのはよくないよ。","ENG":"Horizon. I know you're still sulking, but you really shouldn't lie to your elders like that.","TWN":"地平線，就算你再怎麼生氣也不能說謊啊！"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아, 진짜!","JPN":"ああもう……っ！","ENG":"Oh, come on!","TWN":"真是的！"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"기다려! 기다리라니까!","JPN":"待って！　待ってってば！","ENG":"Wait up! Wait for me!","TWN":"等等我！等我啦！"},"stage":{"bg":"CORRIDOR_04","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GIRL_NPC_HORIZON_NULL","text":{"KOREA":"흑……. 흐흑……. 원장님…….","JPN":"ぐすん……ぐすん……先生……","ENG":"*Sniffle...* *Sob…* Headmaster…","TWN":"嗚……嗚嗚嗚……院長……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"저, 정말 있네? 어떻게 여기 있는 줄 알았어?","JPN":"ほ、本当にいた！　どうしてここにいるってわかったの？","ENG":"S-she's really here? How did you know she'd be here?","TWN":"真…真的在這裡？！你怎麼知道她在這裡？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"한가하게 놀라고 있을 시간 없습니다. 손전등을 비춰 보십시오.","JPN":"驚いている暇はありません。懐中電灯で照らしてみてください。","ENG":"There's no time for standing in awe. Shine your flashlight on her.","TWN":"現在沒時間驚訝，請先打開手電筒。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"……옷이 피범벅이잖아? 뛰어놀다 생길 상처는 아닌데?","JPN":"……服が血まみれじゃない！？　こんなの遊びでできる傷じゃないよ！","ENG":"…Her clothes are covered in blood! She didn't get that from playing hide-and-seek, did she?","TWN":"……衣服上怎麼都是血？又不像是在玩的時候弄到的？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇습니다. 총상입니다.","JPN":"はい、銃傷です。","ENG":"Correct. It is a gunshot wound.","TWN":"沒錯，是槍傷。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"상흔 분석 결과, 권총탄이 전박에 출혈을 야기했습니다.","JPN":"傷痕分析の結果、銃弾が前腕に出血を引き起こしました。","ENG":"Analysis suggests a handgun bullet has caused the bleeding in her antebrachium.","TWN":"傷口分析結果，子彈造成前臂出血。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"혈액 손실이 큽니다. 이대로 두면 사망하겠군요.","JPN":"出血量が多いです。このままでは死亡します。","ENG":"She has already lost a significant amount of blood. She's likely to die if left unattended.","TWN":"失血過多，再這樣下去可能會有生命危險。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"대체 어떤 자식이 애한테……!","JPN":"いったいどんなやつが子どもに……！","ENG":"What kind of a jerk would do this to a kid?!","TWN":"到底是哪個傢伙竟然對一個小孩……！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"엠마는 내가 업을게! 어서 진료소로 옮기자!","JPN":"エマはアタシが負ぶってく！　診療所に行こう！","ENG":"I'll carry Emma! Let's get her to a clinic!","TWN":"我來揹愛瑪！要趕快去診所才行！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"잠깐. 발소리가 들립니다. 휴먼. 한 명이 아니군요.","JPN":"ストップ。足音です、ヒューマン。一人ではありませんね。","ENG":"One moment. I hear footsteps, human. And it's not just one person.","TWN":"等等，有腳步聲，聽起來不只一個人。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"한 명이 아니라고? 민우 아저씨랑 자경단 사람들 아닐까?","JPN":"一人じゃない？　マツダおじさんと自警団の人じゃないかな？","ENG":"It's not just one person? Maybe it's Mr. Minwoo and the neighborhood watch?","TWN":"不只一個人？會是民宇叔叔和自衛隊的人嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……그렇다면 다행입니다만.","JPN":"……ならいいのですが。","ENG":"…If only that were the case.","TWN":"……是就好了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HERETIC_NPC_NULL_A","text":{"KOREA":"주교님의 명령이다! 샅샅이 수색해서 찾아내!","JPN":"司教様の命令だ！　隅々まで捜索して探し出せ！","ENG":"Bishop's orders! Search every corner and find her!","TWN":"主教有令！仔細地搜！把她給我找出來！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERETIC_NPC_NULL_A","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HERETIC_NPC_NULL_A","text":{"KOREA":"경찰에게 신고라도 했다간 우리의 숙원이 물거품이 된다! 서둘러!","JPN":"警察に通報でもされたら我々の宿願が水の泡になる！　急げ！","ENG":"If she manages to call the police, our most sacred yearning could be foiled! Hurry!","TWN":"萬一她去報警，那我們的努力都會化作泡影！動作快！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERETIC_NPC_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HERETIC_NPC_NULL_B","text":{"KOREA":"여기! 여기 핏자국이다! 그 꼬마가 남긴 게 틀림없어!","JPN":"ここだ！　ここに血痕がある！　あのチビのものに違いない！","ENG":"Over here! A blood trail! It must be from the kid!","TWN":"這裡！這裡有血跡！一定是那小鬼的！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERETIC_NPC_NULL_B","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"엠마라고 했습니까. 위험한 휴먼들과 엮인 모양이군요.","JPN":"エマと言いましたか。危険なヒューマンに絡まれたようですね。","ENG":"Emma, was it. It seems you've gotten mixed up with rather dangerous humans.","TWN":"你叫愛瑪嗎？你和那些危險人物似乎有過節？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GIRL_NPC_HORIZON_NULL","text":{"KOREA":"응…… 술래하기 싫어서 여기 숨었는데…… 이상한 아저씨들이 모여 있어서…….","JPN":"……鬼ごっこ中にここに隠れたら……変なおじさんたちが集まってきて……","ENG":"Yeah… I hid here because I didn't want to get found… But then these strange men were here…","TWN":"嗯……我不想玩捉迷藏就躲在這裡……結果有一群奇怪的叔叔……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"대답하지 말고 체력을 아끼십시오. 휴먼. 그러다 죽으면 개죽음입니다.","JPN":"答えなくていいので体力を温存してください、ヒューマン。さもないと犬死するだけです。","ENG":"Try not to speak and conserve your energy, human. Otherwise, you'll die like a stray dog.","TWN":"人類，不要說話，你要保留體力。否則你死也不會瞑目。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"레이첼은 이 휴먼을 데리고 먼저 가시죠.","JPN":"レイチェルはこのヒューマンを連れて先に行ってください。","ENG":"Take this human and go ahead, Rachel.","TWN":"瑞秋，你先帶這個人類離開。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"뭐? 그러면 넌 어떡하려고?","JPN":"え？　あんたはどうするの？","ENG":"What? Then what about you?","TWN":"什麼？你想做什麼？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"아이를 업고 달리면 당신 체력으로는 금방 따라잡힐 겁니다.","JPN":"子どもを負ぶった状態で走ったとしても、あなたの体力ではすぐ追いつかれるでしょう。","ENG":"Given your stamina, they'll catch you if you run with the child on your back.","TWN":"憑你的體力，揹著一個孩子是跑不遠的，很快就會被抓到。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제가 저들을 유인하겠습니다. 그동안 여길 나가서 자경단에 상황을 전하십시오.","JPN":"私が彼らをおびき寄せます。その間にここから出て、自警団に状況を伝えてください。","ENG":"So I will cause a distraction to lure them away. Make your escape and inform the neighborhood watch of the situation.","TWN":"我來吸引他們的注意力，你就趁機會逃跑，把這個情況告訴自衛隊。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"말도 안 되는 소리 하지 마! 그러다 네가 저 사람들한테 잡히면 어쩌려고!","JPN":"バカなこと言わないで！　そんなことしてあんたがあの人たちに捕まったらどうするの！","ENG":"Don't be ridiculous! What if they catch you?!","TWN":"怎麼可以！萬一你被他們抓到的話怎麼辦！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……잘 타일러 보겠습니다.","JPN":"……よく言い聞かせてみます。","ENG":"I will try to… coax them into standing down.","TWN":"……我會好言相勸的。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"HERETIC_NPC_NULL_B","text":{"KOREA":"저기다! 누군가 있어!","JPN":"あそこだ！　誰かがいるぞ！","ENG":"Look! There's someone over there!","TWN":"在那裡！那裡有人！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HERETIC_NPC_NULL_A","text":{"KOREA":"그 꼬마의 친구인가? 놓치지 마라!","JPN":"あのチビの仲間か？　逃すな！","ENG":"A friend of the girl, perhaps? Don't let them get away!","TWN":"是那小鬼的朋友嗎？抓住她們！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"저, 저 바보……! 사람이 말하면 들어야 할 거 아냐?!","JPN":"あ、あのバカ……！　人の話を全然聞かないじゃない！","ENG":"That idiot! She didn't even let me finish!","TWN":"那個笨蛋……！都不聽人家說話！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_RIFLE_FIRE_02"},{"id":"L7_1","type":"dialog","speaker":"GIRL_NPC_HORIZON_NULL","text":{"KOREA":"언니……. 나, 너무 추워…….","JPN":"お姉ちゃん……エマ、寒いよ……","ENG":"Rachel… I'm s-so cold…","TWN":"姊姊……我好冷……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"읏…….","JPN":"うっ……","ENG":"Ugh…","TWN":"唔……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"으이씨, 진짜! 내가 못 살아!","JPN":"もぉ、まったく！","ENG":"Argh! Dang it! You've got to be kidding me!","TWN":"可惡！真是逼死我！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"조금만 참아! 언니가 진료소로 데려가 줄게!","JPN":"もう少しだけ耐えて！　お医者さんのところに連れていってあげるから！","ENG":"Hang in there, kid! I'll get you to a clinic!","TWN":"你忍耐一下！姊姊馬上帶你去診所！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};